@namespace sv_dffa3219f45d46d8a4ae89120bd8abd0.Components.Board

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-1">@Task.Priority</span>
        <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        <div class="mt-2 d-flex gap-1">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-sm btn-outline-secondary" @onclick="OnMoveLeft">← Move Left</button>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-sm btn-outline-secondary" @onclick="OnMoveRight">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@namespace sv_dffa3219f45d46d8a4ae89120bd8abd0.Components.Board

<div class="card border-primary mt-2">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="_title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="_assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="_priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="_dueDate" />
        </div>
        <div class="d-flex gap-1">
            <button class="btn btn-sm btn-primary" @onclick="HandleSave" disabled="@string.IsNullOrWhiteSpace(_title)">Save</button>
            <button class="btn btn-sm btn-secondary" @onclick="OnCancel">Cancel</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string _title = string.Empty;
    private string _assignee = string.Empty;
    private string _priority = "Medium";
    private DateTime _dueDate = DateTime.Today.AddDays(7);

    private async Task HandleSave()
    {
        await OnSave.InvokeAsync((_title, _assignee, _priority, _dueDate));
        _title = string.Empty;
        _assignee = string.Empty;
        _priority = "Medium";
        _dueDate = DateTime.Today.AddDays(7);
    }
}

@namespace sv_dffa3219f45d46d8a4ae89120bd8abd0.Components.Board

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body" style="min-height: 200px; overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeft="() => OnMoveTask.InvokeAsync((task.Id, MoveDirection.Left))"
                          OnMoveRight="() => OnMoveTask.InvokeAsync((task.Id, MoveDirection.Right))" />
            }

            @if (_showForm)
            {
                <AddTaskForm OnSave="HandleTaskCreated" OnCancel="() => _showForm = false" />
            }
            else
            {
                <button class="btn btn-sm btn-outline-primary w-100 mt-2" @onclick="() => _showForm = true">+ Add Task</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = string.Empty;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<(int TaskId, MoveDirection Direction)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate, string Status)> OnAddTask { get; set; }

    private bool _showForm;

    private async Task HandleTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate) args)
    {
        await OnAddTask.InvokeAsync((args.Title, args.Assignee, args.Priority, args.DueDate, ColumnName));
        _showForm = false;
    }

    public enum MoveDirection { Left, Right }
}

@namespace sv_dffa3219f45d46d8a4ae89120bd8abd0.Components.Board

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? string.Empty);
    }
}

@page "/board"
@using sv_dffa3219f45d46d8a4ae89120bd8abd0.Components.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (_loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (_error is not null)
{
    <div class="alert alert-danger">
        <strong>Error loading tasks:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats TotalCount="_allTasks.Count"
                TodoCount="TodoTasks.Count"
                InProgressCount="InProgressTasks.Count"
                DoneCount="DoneTasks.Count"
                OverdueCount="_allTasks.Count(t => t.DueDate < DateTime.Today)" />

    <BoardSearchBar SearchText="@_searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="FilteredTodoTasks"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      OnMoveTask="HandleMoveTask"
                      OnAddTask="HandleAddTask" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="FilteredInProgressTasks"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      OnMoveTask="HandleMoveTask"
                      OnAddTask="HandleAddTask" />

        <KanbanColumn ColumnName="Done"
                      Tasks="FilteredDoneTasks"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      OnMoveTask="HandleMoveTask"
                      OnAddTask="HandleAddTask" />
    </div>
}

@code {
    private List<TaskItem> _allTasks = new();
    private string _searchText = string.Empty;
    private bool _loading = true;
    private string? _error;

    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];

    // Unfiltered column lists (for stats)
    private List<TaskItem> TodoTasks => _allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> InProgressTasks => _allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> DoneTasks => _allTasks.Where(t => t.Status == "Done").ToList();

    // Search-filtered column lists (for display)
    private List<TaskItem> FilteredTodoTasks => ApplySearch(TodoTasks);
    private List<TaskItem> FilteredInProgressTasks => ApplySearch(InProgressTasks);
    private List<TaskItem> FilteredDoneTasks => ApplySearch(DoneTasks);

    private List<TaskItem> ApplySearch(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(_searchText))
            return tasks;
        return tasks.Where(t => t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        _loading = true;
        _error = null;
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private void HandleSearchChanged(string searchText)
    {
        _searchText = searchText;
    }

    private async Task HandleMoveTask((int TaskId, KanbanColumn.MoveDirection Direction) args)
    {
        var task = _allTasks.FirstOrDefault(t => t.Id == args.TaskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(Statuses, task.Status);
        var newIndex = args.Direction == KanbanColumn.MoveDirection.Left ? currentIndex - 1 : currentIndex + 1;

        if (newIndex < 0 || newIndex >= Statuses.Length) return;

        var newStatus = Statuses[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            await LoadTasks();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }

    private async Task HandleAddTask((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            // If the task was created with a different status than the column, update it
            if (newTask.Status != args.Status)
            {
                await TaskService.UpdateTaskStatusAsync(newTask.Id, args.Status);
            }
            await LoadTasks();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }
}

