@using sv_dffa3219f45d46d8a4ae89120bd8abd0.Components.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (_loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (_error is not null)
{
    <div class="alert alert-danger">
        <strong>Error loading tasks:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats TotalCount="_allTasks.Count"
                TodoCount="TodoTasks.Count"
                InProgressCount="InProgressTasks.Count"
                DoneCount="DoneTasks.Count"
                OverdueCount="_allTasks.Count(t => t.DueDate < DateTime.Today)" />

    <BoardSearchBar SearchText="@_searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="FilteredTodoTasks"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      OnMoveTask="HandleMoveTask"
                      OnAddTask="HandleAddTask" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="FilteredInProgressTasks"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      OnMoveTask="HandleMoveTask"
                      OnAddTask="HandleAddTask" />

        <KanbanColumn ColumnName="Done"
                      Tasks="FilteredDoneTasks"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      OnMoveTask="HandleMoveTask"
                      OnAddTask="HandleAddTask" />
    </div>
}

@code {
    private List<TaskItem> _allTasks = new();
    private string _searchText = string.Empty;
    private bool _loading = true;
    private string? _error;

    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];

    // Unfiltered column lists (for stats)
    private List<TaskItem> TodoTasks => _allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> InProgressTasks => _allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> DoneTasks => _allTasks.Where(t => t.Status == "Done").ToList();

    // Search-filtered column lists (for display)
    private List<TaskItem> FilteredTodoTasks => ApplySearch(TodoTasks);
    private List<TaskItem> FilteredInProgressTasks => ApplySearch(InProgressTasks);
    private List<TaskItem> FilteredDoneTasks => ApplySearch(DoneTasks);

    private List<TaskItem> ApplySearch(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(_searchText))
            return tasks;
        return tasks.Where(t => t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        _loading = true;
        _error = null;
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private void HandleSearchChanged(string searchText)
    {
        _searchText = searchText;
    }

    private async Task HandleMoveTask((int TaskId, KanbanColumn.MoveDirection Direction) args)
    {
        var task = _allTasks.FirstOrDefault(t => t.Id == args.TaskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(Statuses, task.Status);
        var newIndex = args.Direction == KanbanColumn.MoveDirection.Left ? currentIndex - 1 : currentIndex + 1;

        if (newIndex < 0 || newIndex >= Statuses.Length) return;

        var newStatus = Statuses[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            await LoadTasks();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }

    private async Task HandleAddTask((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            // If the task was created with a different status than the column, update it
            if (newTask.Status != args.Status)
            {
                await TaskService.UpdateTaskStatusAsync(newTask.Id, args.Status);
            }
            await LoadTasks();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }
}
"}

