+        <div class="card-header d-flex justify-content-between align-items-center">
+            <h5 class="mb-0">@ColumnName</h5>
+            <span class="badge bg-secondary">@Tasks.Count</span>
+        </div>
+        <div class="card-body" style="min-height: 200px; overflow-y: auto;">
+            @foreach (var task in Tasks)
+            {
+                <TaskCard Task="task"
+                          ShowMoveLeft="ShowMoveLeft"
+                          ShowMoveRight="ShowMoveRight"
+                          OnMoveLeft="() => OnMoveTask.InvokeAsync((task.Id, MoveDirection.Left))"
+                          OnMoveRight="() => OnMoveTask.InvokeAsync((task.Id, MoveDirection.Right))" />
+            }
+
+            @if (_showForm)
+            {
+                <AddTaskForm OnSave="HandleTaskCreated" OnCancel="() => _showForm = false" />
+            }
+            else
+            {
+                <button class="btn btn-sm btn-outline-primary w-100 mt-2" @onclick="() => _showForm = true">+ Add Task</button>
+            }
+        </div>
+    </div>
+</div>
+
+@code {
+    [Parameter, EditorRequired] public string ColumnName { get; set; } = string.Empty;
+    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
+    [Parameter] public bool ShowMoveLeft { get; set; }
+    [Parameter] public bool ShowMoveRight { get; set; }
+    [Parameter] public EventCallback<(int TaskId, MoveDirection Direction)> OnMoveTask { get; set; }
+    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate, string Status)> OnAddTask { get; set; }
+
+    private bool _showForm;
+
+    private async Task HandleTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate) args)
+    {
+        await OnAddTask.InvokeAsync((args.Title, args.Assignee, args.Priority, args.DueDate, ColumnName));
+        _showForm = false;
+    }
+
+    public enum MoveDirection { Left, Right }
+}
